<template>
  <div class="home recycle-scroller-demo">
    <div class="tool-bar">
      <button @mousedown="addOneTalkMsg">addOneTalkMsg</button>
      <button @mousedown="addOneHistory">addOneHistory</button>
      <button @mousedown="resetAll">resetAll</button>
      <input v-model="pageMode"
        type="checkbox" /> page mode
    </div>
    <DynamicScroller :items="list"
      key-field="id"
      ref="scroller"
      class="talk_list"
      @resize="resize"
      :page-mode="pageMode"
      :buffer="20"
      :min-item-height="32">
      <!-- :item-height="32" -->
      <!-- , index, active -->
      <template slot-scope="{ item, index, active }">
        <DynamicScrollerItem :item="item"
          :active="active"
          :watchData="true"
          :emitResize="true"
          :size-dependencies="[item.message]"
          :class="{
            message_item: true,
            is_own_post: user == item.name
          }"
          :data-index="index">
          <div class="name"
            @click="clickItem(item)">
            {{item.name}}：
          </div>
          <div class="text_message">{{item.id}}-{{ item.message }}</div>
        </DynamicScrollerItem>
      </template>
    </DynamicScroller>
  </div>
</template>

<script>
// @ is an alias to /src
const base64Map = {
  0: 'A',
  17: 'R',
  34: 'i',
  51: 'z',
  1: 'B',
  18: 'S',
  35: 'j',
  52: '0',
  2: 'C',
  19: 'T',
  36: 'k',
  53: '1',
  3: 'D',
  20: 'U',
  37: 'l',
  54: '2',
  4: 'E',
  21: 'V',
  38: 'm',
  55: '3',
  5: 'F',
  22: 'W',
  39: 'n',
  56: '4',
  6: 'G',
  23: 'X',
  40: 'o',
  57: '5',
  7: 'H',
  24: 'Y',
  41: 'p',
  58: '6',
  8: 'I',
  25: 'Z',
  42: ' q',
  59: '7',
  9: 'J　',
  26: ' a',
  43: 'r',
  60: 8,
  10: 'K',
  27: 'b',
  44: 's',
  61: 9,
  11: 'L',
  28: 'c',
  45: 't',
  62: '+',
  12: 'M',
  29: 'd',
  46: 'u',
  63: '/',
  13: 'N',
  30: 'e',
  47: 'v',
  14: 'O',
  31: 'f',
  48: 'w',
  15: 'P',
  32: 'g',
  49: 'x',
  16: 'Q',
  33: 'h',
  50: 'y'
}
export default {
  name: 'home',
  data () {
    const list = new Array(50).fill(null).map((v, i) => {
      const message = new Array(Math.random() * 64 | 0).fill(null).map(v => {
        return base64Map[(Math.random() * 64 | 0)]
      }).join('')
      return {
        id: i,
        name: Math.random() > 0.5 ? 'TOM' : 'Ronan',
        message,
        height: message
      }
    }).reverse()
    return {
      list,
      user: 'TOM',
      pageMode: false
    }
  },
  components: {
  },
  mounted () {
  },
  methods: {
    clickItem (item) {
      console.log(item.id)
    },
    resize () {
      console.log('scoller resize', this.$refs.scroller)
    },
    resetAll () {
      this.list = []
    },
    addOneTalkMsg () {
      this.list.unshift({
        name: Math.random() > 0.5 ? 'TOM' : 'Ronan',
        message: new Array(Math.random() * 64 | 0).fill(null).map(v => {
          return base64Map[(Math.random() * 64 | 0)]
        }).join(''),
        id: this.list.length,
        height: 100
      })
      this.$nextTick(() => {
        this.$refs.scroller.$el.scrollTop = 0
      })
    },
    addOneHistory () {
      this.list.push({
        name: Math.random() > 0.5 ? 'TOM' : 'Ronan',
        message: new Array(Math.random() * 64 | 0).fill(null).map(v => {
          return base64Map[(Math.random() * 64 | 0)]
        }).join(''),
        id: this.list.length
      })
    }
  }
}
</script>
<style lang="less" scoped>
  .talk_list {
    transform: rotate(180deg);
    background-color: rgba(214, 214, 214, 0.5);
    .message_item {
      padding: 12px 12px;
      display: flex;
      align-items: center;
      transform: rotate(180deg);
      &.is_own_post {
        flex-direction: row-reverse;
      }
      .text_message {
        word-break: break-all;
        white-space: pre-wrap;
        background-color: rgba(209, 209, 209, 0.829);
        width: 50%;
        padding: 10px 10px;
        border-radius: 10px;
      }
    }
  }
</style>
<style lang="less" >
  .talk_list {
    .vue-recycle-scroller__item-view.hover .text_message {
      background-color: #fff;
      color: rgb(192, 173, 87);
    }
  }
</style>
